export interface AuditLog {
  record(event: string): Promise<void>;
}

export interface OrderStore {
  save(id: string): Promise<void>;
}

export async function submitOrder(
  store: OrderStore,
  audit: AuditLog,
  id: string,
): Promise<void> {
  await store.save(id);
  audit.record("order-submitted:" + id);
}
